import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, Flashcard } from "../types";

const API_KEY = process.env.API_KEY || '';

// Initialize safely
let ai: GoogleGenAI | null = null;
if (API_KEY) {
  ai = new GoogleGenAI({ apiKey: API_KEY });
}

export const generateChatResponse = async (
  history: ChatMessage[], 
  currentMessage: string, 
  context: string
): Promise<string> => {
  if (!ai) return "API Key not configured.";

  try {
    const model = ai.models;
    const response = await model.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Context: You are a friendly, expert coding tutor. The user is currently studying: ${context}.

      User History: ${JSON.stringify(history.slice(-5))}

      User Question: ${currentMessage}

      Provide a concise, helpful explanation with code examples if relevant. formatted in Markdown.`,
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Chat Error:", error);
    return "Sorry, I encountered an error connecting to the AI.";
  }
};

export const generateFlashcardsForTopic = async (
  topic: string, 
  language: string, 
  difficulty: string
): Promise<Flashcard[]> => {
  if (!ai) return [{ front: "API Key Missing", back: "Please check metadata.json" }];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate 5 educational flashcards for the coding topic: "${topic}". 
      Target audience: ${difficulty} level.
      Language: ${language}.

      Return ONLY a JSON array of objects with "front" (question/concept) and "back" (answer/explanation) properties.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              front: { type: Type.STRING },
              back: { type: Type.STRING }
            },
            required: ['front', 'back']
          }
        }
      }
    });

    const jsonText = response.text || "[]";
    return JSON.parse(jsonText);
  } catch (error) {
    console.error("Flashcard Gen Error:", error);
    return [{ front: "Error", back: "Could not generate cards." }];
  }
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { AppTheme, LanguageCode, Course, Level, Unit } from '../types';
import { UI_TEXT } from '../constants';

interface AppContextType {
  theme: AppTheme;
  toggleTheme: () => void;
  language: LanguageCode;
  setLanguage: (lang: LanguageCode) => void;
  t: (key: string) => string;
  selectedCourse: Course | null;
  selectCourse: (course: Course | null) => void;
  selectedLevel: Level | null;
  selectLevel: (level: Level | null) => void;
  selectedUnit: Unit | null;
  selectUnit: (unit: Unit | null) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<AppTheme>('light');
  const [language, setLanguage] = useState<LanguageCode>('en');
  const [selectedCourse, setSelectedCourse] = useState<Course | null>(null);
  const [selectedLevel, setSelectedLevel] = useState<Level | null>(null);
  const [selectedUnit, setSelectedUnit] = useState<Unit | null>(null);

  // Apply theme to html element
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const t = (key: string): string => {
    const entry = UI_TEXT[key];
    if (!entry) return key;
    return entry[language] || entry['en'];
  };

  return (
    <AppContext.Provider value={{
      theme,
      toggleTheme,
      language,
      setLanguage,
      t,
      selectedCourse,
      selectCourse: (c) => { setSelectedCourse(c); setSelectedLevel(null); setSelectedUnit(null); },
      selectedLevel,
      selectLevel: (l) => { setSelectedLevel(l); setSelectedUnit(null); },
      selectedUnit,
      selectUnit: setSelectedUnit
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

