import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { generateChatResponse } from '../services/geminiService';
import { ChatMessage } from '../types';
import { MessageSquare, Send, Sparkles, X, Minimize2, Maximize2 } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

export const AIChat: React.FC = () => {
  const { t, selectedUnit, selectedCourse } = useApp();
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);

  const toggleChat = () => setIsOpen(!isOpen);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const context = selectedUnit 
      ? `Course: ${selectedCourse?.name}, Unit: ${selectedUnit.title}, Content: ${selectedUnit.content.substring(0, 100)}...`
      : "General Programming";

    const responseText = await generateChatResponse(messages, userMsg.text, context);

    const botMsg: ChatMessage = { role: 'model', text: responseText, timestamp: Date.now() };
    setMessages(prev => [...prev, botMsg]);
    setLoading(false);
  };

  if (!isOpen) {
    return (
      <button 
        onClick={toggleChat}
        className="fixed bottom-6 right-6 w-14 h-14 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-full shadow-xl shadow-blue-500/40 flex items-center justify-center text-white hover:scale-110 transition-transform z-40 active:scale-95"
      >
        <Sparkles size={24} />
      </button>
    );
  }

  return (
    <div className={`fixed bottom-6 right-6 w-full md:w-[400px] bg-white dark:bg-gray-900 rounded-3xl shadow-2xl z-40 flex flex-col transition-all duration-300 border border-gray-100 dark:border-gray-800 overflow-hidden ${isMinimized ? 'h-[70px]' : 'h-[600px] max-h-[80vh]'}`}>

      {/* Header */}
      <div className="h-16 bg-white/90 dark:bg-gray-900/90 backdrop-blur-md flex items-center justify-between px-5 border-b border-gray-100 dark:border-gray-800 absolute top-0 left-0 right-0 z-10">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-indigo-100 dark:bg-indigo-900/30 flex items-center justify-center text-indigo-600 dark:text-indigo-400">
            <Sparkles size={16} />
          </div>
          <div>
            <h3 className="font-bold text-sm dark:text-white">{t('ai_tutor')}</h3>
            {!isMinimized && <p className="text-[10px] text-green-500 font-medium flex items-center gap-1"><span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"/> Online</p>}
          </div>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={() => setIsMinimized(!isMinimized)} className="p-2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200">
            {isMinimized ? <Maximize2 size={16} /> : <Minimize2 size={16} />}
          </button>
          <button onClick={toggleChat} className="p-2 text-gray-400 hover:text-red-500">
            <X size={18} />
          </button>
        </div>
      </div>

      {/* Messages */}
      {!isMinimized && (
        <>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 pt-20 pb-4 space-y-4 bg-gray-50/50 dark:bg-black/20">
            {messages.length === 0 && (
              <div className="text-center text-gray-400 mt-20 p-6">
                <MessageSquare size={48} className="mx-auto mb-4 opacity-20" />
                <p className="text-sm">{t('type_message')}</p>
              </div>
            )}
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3.5 rounded-2xl text-sm leading-relaxed shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-br-none' 
                    : 'bg-white dark:bg-gray-800 dark:text-gray-200 border border-gray-100 dark:border-gray-700 rounded-bl-none'
                }`}>
                  <ReactMarkdown>{msg.text}</ReactMarkdown>
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex justify-start">
                <div className="bg-white dark:bg-gray-800 p-3 rounded-2xl rounded-bl-none shadow-sm border border-gray-100 dark:border-gray-700">
                  <div className="flex gap-1">
                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Input */}
          <div className="p-4 bg-white dark:bg-gray-900 border-t border-gray-100 dark:border-gray-800">
            <div className="relative">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder={t('type_message')}
                className="w-full bg-gray-100 dark:bg-gray-800 text-gray-800 dark:text-white rounded-full py-3.5 pl-5 pr-12 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim()}
                className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-blue-600 rounded-full text-white shadow-lg shadow-blue-500/30 disabled:opacity-50 disabled:shadow-none hover:scale-105 active:scale-95 transition-all"
              >
                <Send size={16} />
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { generateFlashcardsForTopic } from '../services/geminiService';
import { Flashcard } from '../types';
import { Brain, RotateCw, ChevronLeft, ChevronRight, Wand2 } from 'lucide-react';

export const Flashcards: React.FC = () => {
  const { t, selectedUnit, selectedCourse, language } = useApp();
  const [cards, setCards] = useState<Flashcard[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleGenerate = async () => {
    if (!selectedUnit) return;
    setLoading(true);
    const topic = `${selectedCourse?.name} - ${selectedUnit.title}`;
    const generated = await generateFlashcardsForTopic(topic, language, 'Beginner');
    setCards(generated);
    setCurrentIndex(0);
    setIsFlipped(false);
    setLoading(false);
  };

  if (!selectedUnit) return null;

  return (
    <div className="mt-12 mb-8">
      <div className="flex items-center justify-between mb-6">
        <h3 className="text-xl font-bold dark:text-white flex items-center gap-2">
          <Brain className="text-purple-500" />
          {t('flashcards')}
        </h3>
        {cards.length === 0 && (
          <button 
            onClick={handleGenerate}
            disabled={loading}
            className="flex items-center gap-2 px-4 py-2 bg-gray-900 dark:bg-white text-white dark:text-black rounded-xl text-sm font-semibold hover:opacity-90 transition-all active:scale-95 disabled:opacity-50"
          >
            {loading ? <RotateCw className="animate-spin" size={16} /> : <Wand2 size={16} />}
            {t('generate_flashcards')}
          </button>
        )}
      </div>

      {loading && (
        <div className="h-64 flex items-center justify-center bg-gray-50 dark:bg-gray-800 rounded-3xl border border-dashed border-gray-300 dark:border-gray-700">
           <div className="text-center">
             <div className="w-10 h-10 border-4 border-purple-500 border-t-transparent rounded-full animate-spin mx-auto mb-3" />
             <p className="text-gray-500 text-sm">Generating AI Cards...</p>
           </div>
        </div>
      )}

      {!loading && cards.length > 0 && (
        <div className="relative h-64 perspective-1000 group cursor-pointer" onClick={() => setIsFlipped(!isFlipped)}>
          <div className={`relative w-full h-full duration-500 preserve-3d transition-transform ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* Front */}
            <div className="absolute w-full h-full backface-hidden bg-white dark:bg-gray-800 rounded-3xl shadow-xl shadow-purple-500/5 dark:shadow-purple-900/10 border border-gray-100 dark:border-gray-700 flex flex-col items-center justify-center p-8 text-center hover:scale-[1.02] transition-transform">
              <span className="text-xs font-bold tracking-wider text-purple-500 mb-4 uppercase">Question</span>
              <p className="text-xl font-medium text-gray-800 dark:text-gray-100">{cards[currentIndex].front}</p>
              <p className="absolute bottom-4 text-xs text-gray-400">Click to flip</p>
            </div>

            {/* Back */}
            <div className="absolute w-full h-full backface-hidden rotate-y-180 bg-gradient-to-br from-purple-600 to-indigo-700 text-white rounded-3xl shadow-xl flex flex-col items-center justify-center p-8 text-center">
              <span className="text-xs font-bold tracking-wider text-white/60 mb-4 uppercase">Answer</span>
              <p className="text-lg font-medium">{cards[currentIndex].back}</p>
            </div>
          </div>
        </div>
      )}

      {/* Controls */}
      {!loading && cards.length > 0 && (
        <div className="flex items-center justify-center gap-6 mt-6">
          <button 
            onClick={() => { setCurrentIndex(prev => Math.max(0, prev - 1)); setIsFlipped(false); }}
            disabled={currentIndex === 0}
            className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-30 dark:text-white"
          >
            <ChevronLeft size={20} />
          </button>
          <span className="text-sm font-medium text-gray-500 dark:text-gray-400">
            {currentIndex + 1} / {cards.length}
          </span>
          <button 
            onClick={() => { setCurrentIndex(prev => Math.min(cards.length - 1, prev + 1)); setIsFlipped(false); }}
            disabled={currentIndex === cards.length - 1}
            className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-30 dark:text-white"
          >
            <ChevronRight size={20} />
          </button>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { Flashcards } from './Flashcards';
import { ArrowLeft, CheckCircle, Play, AlertCircle } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

export const UnitView: React.FC = () => {
  const { selectedUnit, selectUnit, t } = useApp();
  const [activeTab, setActiveTab] = useState<'learn' | 'quiz'>('learn');
  const [selectedAnswers, setSelectedAnswers] = useState<Record<string, number>>({});
  const [quizSubmitted, setQuizSubmitted] = useState(false);

  if (!selectedUnit) return null;

  const handleAnswer = (qId: string, idx: number) => {
    if (quizSubmitted) return;
    setSelectedAnswers(prev => ({ ...prev, [qId]: idx }));
  };

  const submitQuiz = () => {
    setQuizSubmitted(true);
  };

  const score = selectedUnit.questions.reduce((acc, q) => {
    return acc + (selectedAnswers[q.id] === q.correctIndex ? 1 : 0);
  }, 0);

  return (
    <div className="animate-fade-in pb-20">
      <button 
        onClick={() => selectUnit(null)} 
        className="mb-6 flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white transition-colors"
      >
        <ArrowLeft size={16} /> {t('back')}
      </button>

      <div className="flex items-center justify-between mb-8">
        <h1 className="text-4xl font-extrabold text-gray-900 dark:text-white tracking-tight">
          {selectedUnit.title}
        </h1>
        <div className="flex bg-gray-100 dark:bg-gray-800 p-1 rounded-xl">
          <button
            onClick={() => setActiveTab('learn')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'learn' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            Learn
          </button>
          <button
            onClick={() => setActiveTab('quiz')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'quiz' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            {t('quiz')}
          </button>
        </div>
      </div>

      {activeTab === 'learn' ? (
        <div className="max-w-3xl">
          <div className="prose prose-lg dark:prose-invert prose-indigo">
            <ReactMarkdown>{selectedUnit.content}</ReactMarkdown>
          </div>
          <div className="my-12 border-t border-gray-100 dark:border-gray-800 pt-8">
            <Flashcards />
          </div>
        </div>
      ) : (
        <div className="max-w-2xl mx-auto space-y-8">
          {selectedUnit.questions.map((q, idx) => {
            const isCorrect = selectedAnswers[q.id] === q.correctIndex;
            return (
              <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                  <span className="text-gray-400 mr-2">{idx + 1}.</span>
                  {q.text}
                </h4>
                <div className="space-y-3">
                  {q.options.map((opt, optIdx) => {
                    let btnClass = "w-full text-left p-4 rounded-xl border transition-all text-sm font-medium ";

                    if (quizSubmitted) {
                      if (optIdx === q.correctIndex) btnClass += "bg-green-100 border-green-500 text-green-700 dark:bg-green-900/30 dark:text-green-300 ";
                      else if (selectedAnswers[q.id] === optIdx) btnClass += "bg-red-50 border-red-200 text-red-600 dark:bg-red-900/20 dark:text-red-300 ";
                      else btnClass += "border-transparent bg-gray-50 dark:bg-gray-700/50 opacity-50 dark:text-gray-400 ";
                    } else {
                      if (selectedAnswers[q.id] === optIdx) btnClass += "border-blue-500 bg-blue-50 text-blue-700 dark:bg-blue-900/20 dark:text-blue-300 ";
                      else btnClass += "border-transparent bg-gray-50 hover:bg-gray-100 dark:bg-gray-700/50 dark:hover:bg-gray-700 dark:text-gray-300 ";
                    }

                    return (
                      <button
                        key={optIdx}
                        onClick={() => handleAnswer(q.id, optIdx)}
                        className={btnClass}
                      >
                        <div className="flex items-center justify-between">
                          {opt}
                          {quizSubmitted && optIdx === q.correctIndex && <CheckCircle size={16} className="text-green-600" />}
                          {quizSubmitted && selectedAnswers[q.id] === optIdx && optIdx !== q.correctIndex && <AlertCircle size={16} className="text-red-500" />}
                        </div>
                      </button>
                    )
                  })}
                </div>
              </div>
            );
          })}

          <div className="sticky bottom-6 bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg p-4 rounded-2xl shadow-lg border border-gray-200 dark:border-gray-700 flex items-center justify-between">
             <div className="text-sm font-semibold text-gray-600 dark:text-gray-300">
               {quizSubmitted ? `Score: ${score} / ${selectedUnit.questions.length}` : 'Complete all questions'}
             </div>
             <button
               onClick={submitQuiz}
               disabled={quizSubmitted || Object.keys(selectedAnswers).length < selectedUnit.questions.length}
               className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 shadow-lg shadow-blue-500/30"
             >
               {t('submit')}
             </button>
          </div>
        </div>
      )}
    </div>
  );
};

