import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, Flashcard, Unit, Question } from "../types";

const API_KEY = process.env.API_KEY || '';

// Initialize safely
let ai: GoogleGenAI | null = null;
if (API_KEY) {
  ai = new GoogleGenAI({ apiKey: API_KEY });
}

export const generateChatResponse = async (
  history: ChatMessage[], 
  currentMessage: string, 
  context: string
): Promise<string> => {
  if (!ai) return "API Key not configured.";

  try {
    const model = ai.models;
    const response = await model.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Context: You are a friendly, expert coding tutor. The user is currently studying: ${context}.

      User History: ${JSON.stringify(history.slice(-5))}

      User Question: ${currentMessage}

      Provide a concise, helpful explanation. Use Markdown for formatting. 
      Use code blocks with the appropriate language tag for any code.
      Keep it encouraging and clean.`,
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Chat Error:", error);
    return "Sorry, I encountered an error connecting to the AI.";
  }
};

export const generateFlashcardsForTopic = async (
  topic: string, 
  language: string, 
  difficulty: string
): Promise<Flashcard[]> => {
  if (!ai) return [{ front: "API Key Missing", back: "Please check metadata.json" }];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate 5 educational flashcards for the coding topic: "${topic}". 
      Target audience: ${difficulty} level.
      Language: ${language}.

      Return ONLY a JSON array of objects with "front" (question/concept) and "back" (answer/explanation) properties.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              front: { type: Type.STRING },
              back: { type: Type.STRING }
            },
            required: ['front', 'back']
          }
        }
      }
    });

    const jsonText = response.text || "[]";
    return JSON.parse(jsonText);
  } catch (error) {
    console.error("Flashcard Gen Error:", error);
    return [{ front: "Error", back: "Could not generate cards." }];
  }
};

export const generateSyllabus = async (
  courseName: string,
  level: string,
  focus: string = "general"
): Promise<Unit[]> => {
  if (!ai) return [];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create a syllabus of 5 units for learning ${courseName} at a ${level} level.
      Focus area: ${focus}.

      Return a JSON array of objects with 'id', 'title', 'content' (empty string), and 'questions' (empty array).
      The 'id' should be unique-ish (e.g., 'unit_1').`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              title: { type: Type.STRING },
              content: { type: Type.STRING }, // Initial empty
              questions: { type: Type.ARRAY, items: { type: Type.STRING } } // Initial empty
            },
            required: ['id', 'title']
          }
        }
      }
    });

    const units = JSON.parse(response.text || "[]");
    // Ensure structure
    return units.map((u: any, i: number) => ({
      id: `${courseName}_${level}_${i}_${Date.now()}`,
      title: u.title,
      content: "",
      questions: []
    }));

  } catch (error) {
    console.error("Syllabus Gen Error:", error);
    return [];
  }
};

export const generateUnitContent = async (
  courseName: string,
  unitTitle: string,
  level: string
): Promise<{ content: string; questions: Question[] }> => {
  if (!ai) return { content: "Error loading content.", questions: [] };

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Write a comprehensive educational lesson for ${courseName} (${level}) on the topic: "${unitTitle}".

      Output JSON with two fields:
      1. 'content': A Markdown formatted string explaining the concept with code examples. Use Headers, bold text, and code blocks.
      2. 'questions': An array of 3 multiple choice questions to test understanding. Each question object has 'id', 'text', 'options' (array of 4 strings), and 'correctIndex' (0-3).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            content: { type: Type.STRING },
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  text: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctIndex: { type: Type.INTEGER }
                },
                required: ['text', 'options', 'correctIndex']
              }
            }
          },
          required: ['content', 'questions']
        }
      }
    });

    const data = JSON.parse(response.text || "{}");

    // Add IDs if missing
    const questions = (data.questions || []).map((q: any, i: number) => ({
      ...q,
      id: q.id || `q_${Date.now()}_${i}`
    }));

    return {
      content: data.content || "No content generated.",
      questions: questions
    };

  } catch (error) {
    console.error("Unit Content Gen Error:", error);
    return {
      content: "Failed to generate content. Please try again.",
      questions: []
    };
  }
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { AppTheme, LanguageCode, Course, Level, Unit } from '../types';
import { UI_TEXT, COURSES as DEFAULT_COURSES } from '../constants';

interface AppContextType {
  theme: AppTheme;
  toggleTheme: () => void;
  language: LanguageCode;
  setLanguage: (lang: LanguageCode) => void;
  t: (key: string) => string;
  courses: Course[];
  updateCourseUnits: (courseId: string, levelId: string, units: Unit[]) => void;
  updateUnitContent: (courseId: string, levelId: string, unitId: string, content: string, questions: any[]) => void;
  selectedCourse: Course | null;
  selectCourse: (course: Course | null) => void;
  selectedLevel: Level | null;
  selectLevel: (level: Level | null) => void;
  selectedUnit: Unit | null;
  selectUnit: (unit: Unit | null) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<AppTheme>('light');
  const [language, setLanguage] = useState<LanguageCode>('en');

  // Local state copy of courses to allow mutation (adding generated content)
  const [courses, setCourses] = useState<Course[]>(DEFAULT_COURSES);

  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [selectedLevelId, setSelectedLevelId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | null>(null);

  // Apply theme to html element
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const t = (key: string): string => {
    const entry = UI_TEXT[key];
    if (!entry) return key;
    return entry[language] || entry['en'];
  };

  // Helper getters
  const selectedCourse = courses.find(c => c.id === selectedCourseId) || null;
  const selectedLevel = selectedCourse?.levels.find(l => l.id === selectedLevelId) || null;
  const selectedUnit = selectedLevel?.units.find(u => u.id === selectedUnitId) || null;

  const updateCourseUnits = (courseId: string, levelId: string, units: Unit[]) => {
    setCourses(prev => prev.map(c => {
      if (c.id !== courseId) return c;
      return {
        ...c,
        levels: c.levels.map(l => {
          if (l.id !== levelId) return l;
          return { ...l, units };
        })
      };
    }));
  };

  const updateUnitContent = (courseId: string, levelId: string, unitId: string, content: string, questions: any[]) => {
    setCourses(prev => prev.map(c => {
      if (c.id !== courseId) return c;
      return {
        ...c,
        levels: c.levels.map(l => {
          if (l.id !== levelId) return l;
          return {
            ...l,
            units: l.units.map(u => {
              if (u.id !== unitId) return u;
              return { ...u, content, questions };
            })
          };
        })
      };
    }));
  };

  return (
    <AppContext.Provider value={{
      theme,
      toggleTheme,
      language,
      setLanguage,
      t,
      courses,
      updateCourseUnits,
      updateUnitContent,
      selectedCourse,
      selectCourse: (c) => { 
        setSelectedCourseId(c ? c.id : null); 
        setSelectedLevelId(null); 
        setSelectedUnitId(null); 
      },
      selectedLevel,
      selectLevel: (l) => { 
        setSelectedLevelId(l ? l.id : null); 
        setSelectedUnitId(null); 
      },
      selectedUnit,
      selectUnit: (u) => setSelectedUnitId(u ? u.id : null)
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

import React, { useState, useRef, useEffect } from 'react';
