                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer dark:bg-gray-700 accent-blue-600"
              />
              <div className="flex justify-between text-xs text-gray-400 mt-2">
                <span>1</span>
                <span>10</span>
              </div>
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-4">
                {t('question_types')}
              </label>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                {[
                  { id: 'mcq' as const, label: 'MCQ' },
                  { id: 'frq' as const, label: 'Open Ended' },
                  { id: 'matching' as const, label: 'Matching' }
                ].map((type) => (
                  <button
                    key={type.id}
                    onClick={() => toggleType(type.id)}
                    className={`py-3 px-4 rounded-xl border-2 font-medium transition-all ${
                      selectedTypes.includes(type.id)
                        ? 'border-blue-500 bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400'
                        : 'border-gray-200 dark:border-gray-700 text-gray-500 dark:text-gray-400 hover:border-gray-300 dark:hover:border-gray-600'
                    }`}
                  >
                    {type.label}
                  </button>
                ))}
              </div>
            </div>

            <button 
              onClick={handleStartLesson}
              className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold shadow-lg shadow-blue-500/30 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <Play size={20} fill="currentColor" />
              {t('start_lesson')}
            </button>
          </div>
        </div>
      </div>
    );
  }

  // Main Unit View
  const handleMcqAnswer = (qId: string, idx: number) => {
    if (quizSubmitted) return;
    setSelectedAnswers(prev => ({ ...prev, [qId]: idx }));
  };

  const handleMatchingAnswer = (qId: string, term: string, def: string) => {
    if (quizSubmitted) return;
    setMatchingAnswers(prev => ({
      ...prev,
      [qId]: { ...(prev[qId] || {}), [term]: def }
    }));
  };

  return (
    <div className="animate-fade-in pb-20">
      <button 
        onClick={() => selectUnit(null)} 
        className="mb-6 flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white transition-colors"
      >
        <ArrowLeft size={16} /> {t('back')}
      </button>

      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <h1 className="text-3xl md:text-4xl font-extrabold text-gray-900 dark:text-white tracking-tight">
          {selectedUnit.title}
        </h1>
        <div className="flex bg-gray-100 dark:bg-gray-800 p-1 rounded-xl self-start">
          <button
            onClick={() => setActiveTab('learn')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'learn' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            {t('learn')}
          </button>
          <button
            onClick={() => setActiveTab('quiz')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'quiz' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            {t('quiz')}
          </button>
        </div>
      </div>

      {activeTab === 'learn' ? (
        <div className="max-w-4xl">
          <div className="prose prose-lg dark:prose-invert prose-blue max-w-none">
            <ReactMarkdown 
               components={{
                 code: ({node, inline, className, children, ...props}: any) => {
                   if (inline) {
                     return (
                       <code className="bg-gray-100 dark:bg-gray-800 px-1.5 py-0.5 rounded text-sm font-mono text-pink-600 dark:text-pink-400" {...props}>
                         {children}
                       </code>
                     );
                   }
                   return (
                     <div className="my-6 rounded-xl overflow-hidden shadow-2xl bg-[#1e1e1e] border border-gray-700/50">
                       <div className="flex items-center gap-2 px-4 py-3 bg-[#2d2d2d] border-b border-gray-700/50">
                         <div className="w-3 h-3 rounded-full bg-[#ff5f56]" />
                         <div className="w-3 h-3 rounded-full bg-[#ffbd2e]" />
                         <div className="w-3 h-3 rounded-full bg-[#27c93f]" />
                         <div className="ml-2 text-xs text-gray-500 font-mono">code</div>
                       </div>
                       <div className="p-4 overflow-x-auto">
                         <code className="font-mono text-sm text-gray-200 leading-relaxed" {...props}>
                           {children}
                         </code>
                       </div>
                     </div>
                   );
                 }
               }}
            >
              {selectedUnit.content}
            </ReactMarkdown>
          </div>
          <div className="my-12 border-t border-gray-100 dark:border-gray-800 pt-8">
            <Flashcards />
          </div>
        </div>
      ) : (
        <div className="max-w-2xl mx-auto space-y-8">
          {selectedUnit.questions.length === 0 ? (
            <div className="text-center text-gray-500">No questions generated.</div>
          ) : (
             selectedUnit.questions.map((q, idx) => {
                // RENDER MCQ
                if (q.type === 'mcq' && q.options) {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text}
                      </h4>
                      <div className="space-y-3">
                        {q.options.map((opt, optIdx) => {
                          let btnClass = "w-full text-left p-4 rounded-xl border transition-all text-sm font-medium ";
                          if (quizSubmitted) {
                            if (optIdx === q.correctIndex) btnClass += "bg-green-100 border-green-500 text-green-700 dark:bg-green-900/30 dark:text-green-300 ";
                            else if (selectedAnswers[q.id] === optIdx) btnClass += "bg-red-50 border-red-200 text-red-600 dark:bg-red-900/20 dark:text-red-300 ";
                            else btnClass += "border-transparent bg-gray-50 dark:bg-gray-700/50 opacity-50 dark:text-gray-400 ";
                          } else {
                            if (selectedAnswers[q.id] === optIdx) btnClass += "border-blue-500 bg-blue-50 text-blue-700 dark:bg-blue-900/20 dark:text-blue-300 ";
                            else btnClass += "border-transparent bg-gray-50 hover:bg-gray-100 dark:bg-gray-700/50 dark:hover:bg-gray-700 dark:text-gray-300 ";
                          }
                          return (
                            <button key={optIdx} onClick={() => handleMcqAnswer(q.id, optIdx)} className={btnClass}>
                              <div className="flex items-center justify-between">
                                {opt}
                                {quizSubmitted && optIdx === q.correctIndex && <CheckCircle size={16} className="text-green-600" />}
                                {quizSubmitted && selectedAnswers[q.id] === optIdx && optIdx !== q.correctIndex && <AlertCircle size={16} className="text-red-500" />}
                              </div>
                            </button>
                          )
                        })}
                      </div>
                    </div>
                  );
                }

                // RENDER FRQ
                if (q.type === 'frq') {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text}
                      </h4>
                      <textarea 
                        className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-700/50 border border-gray-200 dark:border-gray-700 focus:ring-2 focus:ring-blue-500 outline-none text-gray-900 dark:text-white h-32 mb-4"
                        placeholder={t('type_message')}
                      ></textarea>
                      <button 
                        onClick={() => setShowFrqAnswers(prev => ({...prev, [q.id]: !prev[q.id]}))}
                        className="text-blue-600 dark:text-blue-400 font-semibold text-sm flex items-center gap-2 hover:underline"
                      >
                        <Eye size={16} /> {t('reveal_answer')}
                      </button>
                      {showFrqAnswers[q.id] && (
                        <div className="mt-4 p-4 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-xl text-green-800 dark:text-green-300 text-sm">
                          <strong>{t('model_answer')}:</strong> {q.answer}
                        </div>
                      )}
                    </div>
                  );
                }

                // RENDER MATCHING
                if (q.type === 'matching' && q.pairs) {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text || t('match_pairs')}
                      </h4>
                      <div className="space-y-4">
                        {q.pairs.map((pair, pIdx) => {
                          const currentAnswer = matchingAnswers[q.id]?.[pair.term];
                          const isCorrect = quizSubmitted && currentAnswer === pair.definition;

                          return (
                            <div key={pIdx} className="flex flex-col sm:flex-row sm:items-center gap-4 p-3 bg-gray-50 dark:bg-gray-700/30 rounded-xl">
                              <div className="flex-1 font-semibold text-gray-800 dark:text-gray-200">{pair.term}</div>
                              <div className="hidden sm:block text-gray-400">→</div>
                              <select 
                                value={currentAnswer || ""}
                                onChange={(e) => handleMatchingAnswer(q.id, pair.term, e.target.value)}
                                disabled={quizSubmitted}
                                className={`flex-1 p-2.5 rounded-lg border text-sm outline-none transition-colors ${
                                  quizSubmitted 
                                    ? (isCorrect 
                                        ? "bg-green-100 border-green-500 text-green-800 dark:bg-green-900/40 dark:text-green-200"
                                        : "bg-red-50 border-red-300 text-red-800 dark:bg-red-900/20 dark:text-red-200")
                                    : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-600 text-gray-800 dark:text-white focus:border-blue-500"
                                }`}
                              >
                                <option value="">{t('select_match')}</option>
                                {/* Shuffle options for display in a real app, here simplifying by showing all definitions */}
                                {q.pairs?.map((p) => (
                                  <option key={p.definition} value={p.definition}>{p.definition}</option>
                                ))}
                              </select>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                }
                return null;
            })
          )}

          <div className="sticky bottom-6 bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg p-4 rounded-2xl shadow-lg border border-gray-200 dark:border-gray-700 flex items-center justify-between">
             <div className="text-sm font-semibold text-gray-600 dark:text-gray-300">
               {quizSubmitted ? t('submit') : t('submit')}
             </div>
             <button
               onClick={submitQuiz}
               disabled={quizSubmitted || selectedUnit.questions.length === 0}
               className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 shadow-lg shadow-blue-500/30"
             >
               {t('submit')}
             </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { generateFlashcardsForTopic } from '../services/geminiService';
import { Flashcard } from '../types';
import { Brain, RotateCw, ChevronLeft, ChevronRight, Wand2 } from 'lucide-react';

export const Flashcards: React.FC = () => {
  const { t, selectedUnit, selectedCourse, language } = useApp();
  const [cards, setCards] = useState<Flashcard[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [loading, setLoading] = useState(false);
  const [count, setCount] = useState(5);

  const handleGenerate = async () => {
    if (!selectedUnit) return;
    setLoading(true);
    const topic = `${selectedCourse?.name} - ${selectedUnit.title}`;
    const generated = await generateFlashcardsForTopic(topic, language, 'Beginner', count);
    setCards(generated);
    setCurrentIndex(0);
    setIsFlipped(false);
    setLoading(false);
  };

  if (!selectedUnit) return null;

  return (
    <div className="mt-12 mb-8">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <h3 className="text-xl font-bold dark:text-white flex items-center gap-2">
          <Brain className="text-purple-500" />
          {t('flashcards')}
        </h3>

        {cards.length === 0 && (
          <div className="flex items-center gap-2">
            <div className="flex items-center bg-gray-100 dark:bg-gray-800 rounded-lg px-2 py-1">
              <span className="text-xs font-semibold text-gray-500 dark:text-gray-400 mr-2">{t('count')}:</span>
              <input 
                type="number" 
                min="3" 
                max="10" 
                value={count} 
                onChange={(e) => setCount(Math.max(3, Math.min(10, parseInt(e.target.value) || 3)))}
                className="w-10 bg-transparent text-sm font-bold text-gray-900 dark:text-white outline-none text-center"
              />
            </div>
            <button 
              onClick={handleGenerate}
              disabled={loading}
              className="flex items-center gap-2 px-4 py-2 bg-gray-900 dark:bg-white text-white dark:text-black rounded-xl text-sm font-semibold hover:opacity-90 transition-all active:scale-95 disabled:opacity-50"
            >
              {loading ? <RotateCw className="animate-spin" size={16} /> : <Wand2 size={16} />}
              {t('generate_flashcards')}
            </button>
          </div>
        )}
      </div>

      {loading && (
        <div className="h-64 flex items-center justify-center bg-gray-50 dark:bg-gray-800 rounded-3xl border border-dashed border-gray-300 dark:border-gray-700">
           <div className="text-center">
             <div className="w-10 h-10 border-4 border-purple-500 border-t-transparent rounded-full animate-spin mx-auto mb-3" />
             <p className="text-gray-500 text-sm">Generating AI Cards...</p>
           </div>
        </div>
      )}

      {!loading && cards.length > 0 && (
        <div className="relative h-64 perspective-1000 group cursor-pointer" onClick={() => setIsFlipped(!isFlipped)}>
          <div className={`relative w-full h-full duration-500 preserve-3d transition-transform ${isFlipped ? 'rotate-y-180' : ''}`}>

            {/* Front */}
            <div className="absolute w-full h-full backface-hidden bg-white dark:bg-gray-800 rounded-3xl shadow-xl shadow-purple-500/5 dark:shadow-purple-900/10 border border-gray-100 dark:border-gray-700 flex flex-col items-center justify-center p-8 text-center hover:scale-[1.02] transition-transform">
              <span className="text-xs font-bold tracking-wider text-purple-500 mb-4 uppercase">Question</span>
              <p className="text-xl font-medium text-gray-800 dark:text-gray-100">{cards[currentIndex].front}</p>
              <p className="absolute bottom-4 text-xs text-gray-400">Click to flip</p>
            </div>

            {/* Back */}
            <div className="absolute w-full h-full backface-hidden rotate-y-180 bg-gradient-to-br from-purple-600 to-indigo-700 text-white rounded-3xl shadow-xl flex flex-col items-center justify-center p-8 text-center">
              <span className="text-xs font-bold tracking-wider text-white/60 mb-4 uppercase">Answer</span>
              <p className="text-lg font-medium">{cards[currentIndex].back}</p>
            </div>
          </div>
        </div>
      )}

      {/* Controls */}
      {!loading && cards.length > 0 && (
        <div className="flex items-center justify-center gap-6 mt-6">
          <button 
            onClick={() => { setCurrentIndex(prev => Math.max(0, prev - 1)); setIsFlipped(false); }}
            disabled={currentIndex === 0}
            className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-30 dark:text-white"
          >
            <ChevronLeft size={20} />
          </button>
          <span className="text-sm font-medium text-gray-500 dark:text-gray-400">
            {currentIndex + 1} / {cards.length}
          </span>
          <button 
            onClick={() => { setCurrentIndex(prev => Math.min(cards.length - 1, prev + 1)); setIsFlipped(false); }}
            disabled={currentIndex === cards.length - 1}
            className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700 disabled:opacity-30 dark:text-white"
          >
            <ChevronRight size={20} />
          </button>
        </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { AppTheme, LanguageCode, Course, Level, Unit } from '../types';
import { UI_TEXT, COURSES as DEFAULT_COURSES } from '../constants';

interface AppContextType {
  theme: AppTheme;
  toggleTheme: () => void;
  language: LanguageCode;
  setLanguage: (lang: LanguageCode) => void;
  t: (key: string) => string;
  courses: Course[];
  updateCourseUnits: (courseId: string, levelId: string, units: Unit[]) => void;
  updateUnitContent: (courseId: string, levelId: string, unitId: string, content: string, questions: any[]) => void;
  selectedCourse: Course | null;
  selectCourse: (course: Course | null) => void;
  selectedLevel: Level | null;
  selectLevel: (level: Level | null) => void;
  selectedUnit: Unit | null;
  selectUnit: (unit: Unit | null) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<AppTheme>('light');
  const [language, setLanguage] = useState<LanguageCode>('en');

  // Local state copy of courses to allow mutation (adding generated content)
  const [courses, setCourses] = useState<Course[]>(DEFAULT_COURSES);

  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [selectedLevelId, setSelectedLevelId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | null>(null);

  // Apply theme to html element
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  // Apply direction for RTL languages
  useEffect(() => {
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = language;
  }, [language]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const t = (key: string): string => {
    const entry = UI_TEXT[key];
    if (!entry) return key;
    return entry[language] || entry['en'];
  };

  // Helper getters
  const selectedCourse = courses.find(c => c.id === selectedCourseId) || null;
  const selectedLevel = selectedCourse?.levels.find(l => l.id === selectedLevelId) || null;
  const selectedUnit = selectedLevel?.units.find(u => u.id === selectedUnitId) || null;

  const updateCourseUnits = (courseId: string, levelId: string, units: Unit[]) => {
    setCourses(prev => prev.map(c => {
      if (c.id !== courseId) return c;
      return {
        ...c,
        levels: c.levels.map(l => {
          if (l.id !== levelId) return l;
          return { ...l, units };
        })
      };
    }));
  };

  const updateUnitContent = (courseId: string, levelId: string, unitId: string, content: string, questions: any[]) => {
    setCourses(prev => prev.map(c => {
      if (c.id !== courseId) return c;
      return {
        ...c,
        levels: c.levels.map(l => {
          if (l.id !== levelId) return l;
          return {
            ...l,
            units: l.units.map(u => {
              if (u.id !== unitId) return u;
              return { ...u, content, questions };
            })
          };
        })
      };
    }));
  };

  return (
    <AppContext.Provider value={{
      theme,
      toggleTheme,
      language,
      setLanguage,
      t,
      courses,
      updateCourseUnits,
      updateUnitContent,
      selectedCourse,
      selectCourse: (c) => { 
        setSelectedCourseId(c ? c.id : null); 
        setSelectedLevelId(null); 
        setSelectedUnitId(null); 
      },
      selectedLevel,
      selectLevel: (l) => { 
        setSelectedLevelId(l ? l.id : null); 
        setSelectedUnitId(null); 
      },
      selectedUnit,
      selectUnit: (u) => setSelectedUnitId(u ? u.id : null)
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

import React, { useState } from 'react';
import { AppProvider, useApp } from './context/AppContext';
import { Settings } from './components/Settings';
import { AIChat } from './components/AIChat';
