                                {opt}
                                {quizSubmitted && optIdx === q.correctIndex && <CheckCircle size={16} className="text-green-600" />}
                                {quizSubmitted && selectedAnswers[q.id] === optIdx && optIdx !== q.correctIndex && <AlertCircle size={16} className="text-red-500" />}
                              </div>
                            </button>
                          )
                        })}
                      </div>
                    </div>
                  );
                }

                // RENDER FRQ
                if (q.type === 'frq') {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text}
                      </h4>
                      <textarea 
                        className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-700/50 border border-gray-200 dark:border-gray-700 focus:ring-2 focus:ring-blue-500 outline-none text-gray-900 dark:text-white h-32 mb-4"
                        placeholder={t('type_message')}
                      ></textarea>
                      <button 
                        onClick={() => setShowFrqAnswers(prev => ({...prev, [q.id]: !prev[q.id]}))}
                        className="text-blue-600 dark:text-blue-400 font-semibold text-sm flex items-center gap-2 hover:underline"
                      >
                        <Eye size={16} /> {t('reveal_answer')}
                      </button>
                      {showFrqAnswers[q.id] && (
                        <div className="mt-4 p-4 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-xl text-green-800 dark:text-green-300 text-sm">
                          <strong>{t('model_answer')}:</strong> {q.answer}
                        </div>
                      )}
                    </div>
                  );
                }

                // RENDER MATCHING
                if (q.type === 'matching' && q.pairs) {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text || t('match_pairs')}
                      </h4>
                      <div className="space-y-4">
                        {q.pairs.map((pair, pIdx) => {
                          const currentAnswer = matchingAnswers[q.id]?.[pair.term];
                          const isCorrect = quizSubmitted && currentAnswer === pair.definition;

                          return (
                            <div key={pIdx} className="flex flex-col sm:flex-row sm:items-center gap-4 p-3 bg-gray-50 dark:bg-gray-700/30 rounded-xl">
                              <div className="flex-1 font-semibold text-gray-800 dark:text-gray-200">{pair.term}</div>
                              <div className="hidden sm:block text-gray-400">→</div>
                              <select 
                                value={currentAnswer || ""}
                                onChange={(e) => handleMatchingAnswer(q.id, pair.term, e.target.value)}
                                disabled={quizSubmitted}
                                className={`flex-1 p-2.5 rounded-lg border text-sm outline-none transition-colors ${
                                  quizSubmitted 
                                    ? (isCorrect 
                                        ? "bg-green-100 border-green-500 text-green-800 dark:bg-green-900/40 dark:text-green-200"
                                        : "bg-red-50 border-red-300 text-red-800 dark:bg-red-900/20 dark:text-red-200")
                                    : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-600 text-gray-800 dark:text-white focus:border-blue-500"
                                }`}
                              >
                                <option value="">{t('select_match')}</option>
                                {/* Shuffle options for display in a real app, here simplifying by showing all definitions */}
                                {q.pairs?.map((p) => (
                                  <option key={p.definition} value={p.definition}>{p.definition}</option>
                                ))}
                              </select>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                }
                return null;
            })
          )}

          <div className="sticky bottom-6 bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg p-4 rounded-2xl shadow-lg border border-gray-200 dark:border-gray-700 flex items-center justify-between">
             <div className="text-sm font-semibold text-gray-600 dark:text-gray-300">
               {quizSubmitted ? t('submit') : t('submit')}
             </div>
             <button
               onClick={submitQuiz}
               disabled={quizSubmitted || selectedUnit.questions.length === 0}
               className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 shadow-lg shadow-blue-500/30"
             >
               {t('submit')}
             </button>
          </div>
        </div>
      )}

      {activeTab === 'videos' && (
        <div className="max-w-4xl mx-auto">
          {loadingVideos ? (
             <div className="flex flex-col items-center justify-center py-20">
               <div className="w-12 h-12 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-4" />
               <p className="text-gray-500">{t('searching_videos')}</p>
             </div>
          ) : videos.length === 0 ? (
             <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-3xl border border-gray-100 dark:border-gray-700">
                <AlertTriangle className="mx-auto h-12 w-12 text-yellow-500 mb-4" />
                <h3 className="text-xl font-bold dark:text-white mb-2">{t('unable_to_find_videos')}</h3>
             </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {videos.map((video) => (
                <div key={video.videoId} className="bg-white dark:bg-gray-800 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden hover:shadow-lg transition-shadow">
                  <div className="aspect-video w-full bg-black relative group">
                    <iframe
                      width="100%"
                      height="100%"
                      src={`https://www.youtube-nocookie.com/embed/${video.videoId}?rel=0&modestbranding=1&playsinline=1&enablejsapi=1&origin=${window.location.origin}`}
                      title={video.title}
                      frameBorder="0"
                      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                      referrerPolicy="no-referrer"
                      allowFullScreen
                    ></iframe>
                  </div>
                  <div className="p-5">
                    <h3 className="font-bold text-gray-900 dark:text-white mb-2 line-clamp-2">{video.title}</h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400 line-clamp-3 mb-4">{video.description}</p>
                    <a 
                      href={`https://www.youtube.com/watch?v=${video.videoId}`} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="inline-flex items-center gap-2 text-xs font-semibold text-blue-600 dark:text-blue-400 hover:underline"
                    >
                      <ExternalLink size={14} />
                      Watch on YouTube
                    </a>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export type LanguageCode = 'en' | 'es' | 'fr' | 'de' | 'zh' | 'vi' | 'it' | 'hi' | 'ar' | 'ja' | 'ko' | 'pt' | 'ru' | 'tr';

export type AppTheme = 'light' | 'dark';

export interface TranslationDictionary {
  [key: string]: {
    [code in LanguageCode]: string;
  };
}

export type QuestionType = 'mcq' | 'frq' | 'matching';

export interface Question {
  id: string;
  type: QuestionType;
  text: string;
  // For MCQ
  options?: string[];
  correctIndex?: number;
  // For FRQ
  answer?: string; // Model answer
  // For Matching
  pairs?: { term: string; definition: string }[]; 
}

export interface Unit {
  id: string;
  title: string;
  content: string; // Markdown-like text
  questions: Question[];
}

export interface Level {
  id: 'beginner' | 'intermediate' | 'advanced';
  title: string;
  units: Unit[];
}

export interface Course {
  id: string;
  name: string;
  icon: string; // Lucide icon name or emoji
  description: string;
  levels: Level[];
}

export interface Flashcard {
  front: string;
  back: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface Video {
  videoId: string;
  title: string;
  description: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, Flashcard, Unit, Question, QuestionType, Video } from "../types";

const API_KEY = process.env.API_KEY || '';

// Initialize safely
let ai: GoogleGenAI | null = null;
if (API_KEY) {
  ai = new GoogleGenAI({ apiKey: API_KEY });
}

// Helper to get full language name
const getLanguageName = (code: string) => {
  const map: Record<string, string> = {
    en: "English",
    es: "Spanish",
    fr: "French",
    de: "German",
    zh: "Chinese (Simplified)",
    vi: "Vietnamese",
    it: "Italian",
    hi: "Hindi",
    ar: "Arabic",
    ja: "Japanese",
    ko: "Korean",
    pt: "Portuguese",
    ru: "Russian",
    tr: "Turkish"
  };
  return map[code] || "English";
}

export const generateChatResponse = async (
  history: ChatMessage[], 
  currentMessage: string, 
  context: string,
  languageCode: string = 'en'
): Promise<string> => {
  if (!ai) return "API Key not configured.";

  const lang = getLanguageName(languageCode);

  try {
    const model = ai.models;
    const response = await model.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Context: You are a friendly, expert tutor. The user is currently studying: ${context}.

      User History: ${JSON.stringify(history.slice(-5))}

      User Question: ${currentMessage}

      Instructions:
      1. Provide a concise, helpful explanation in ${lang}.
      2. Use Markdown for formatting. 
      3. Use code blocks with the appropriate language tag for any code.
      4. Keep it encouraging and clean.
      5. Ensure all information included is correct and up-to-date.`,
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Chat Error:", error);
    return "Sorry, I encountered an error connecting to the AI.";
  }
};

export const generateFlashcardsForTopic = async (
  topic: string, 
  languageCode: string, 
  difficulty: string,
  count: number = 5
): Promise<Flashcard[]> => {
  if (!ai) return [{ front: "API Key Missing", back: "Please check metadata.json" }];

  const lang = getLanguageName(languageCode);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate ${count} educational flashcards for the topic: "${topic}". 
      Target audience: ${difficulty} level.
      Output Language: ${lang}.

      Return ONLY a JSON array of objects with "front" (question/concept) and "back" (answer/explanation) properties.
      Ensure the content is in ${lang}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              front: { type: Type.STRING },
              back: { type: Type.STRING }
            },
            required: ['front', 'back']
          }
        }
      }
    });

    const jsonText = response.text || "[]";
    return JSON.parse(jsonText);
  } catch (error) {
    console.error("Flashcard Gen Error:", error);
    return [{ front: "Error", back: "Could not generate cards." }];
  }
};

export const generateSyllabus = async (
  courseName: string,
  level: string,
  focus: string = "general",
  languageCode: string = "en"
): Promise<Unit[]> => {
  if (!ai) return [];

  const lang = getLanguageName(languageCode);

  // Special handling if course is 'Other' or 'Custom'
  const isCustom = courseName.toLowerCase().includes('custom') || courseName.toLowerCase().includes('other');
  const promptContext = isCustom 
    ? `Create a syllabus of 5 units for learning the topic: "${focus}". Level: ${level}.` 
    : `Create a syllabus of 5 units for learning ${courseName} at a ${level} level. Focus area: ${focus}.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `${promptContext}
      Output Language: ${lang}.

      Return a JSON array of objects with 'id', 'title', 'content' (empty string), and 'questions' (empty array).
      The 'id' should be unique-ish (e.g., 'unit_1').`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              title: { type: Type.STRING },
              content: { type: Type.STRING }, // Initial empty
              questions: { type: Type.ARRAY, items: { type: Type.STRING } } // Initial empty
            },
            required: ['id', 'title']
          }
        }
      }
    });

    const units = JSON.parse(response.text || "[]");
    // Ensure structure
    return units.map((u: any, i: number) => ({
      id: `${courseName}_${level}_${i}_${Date.now()}`,
      title: u.title,
      content: "",
      questions: []
    }));

  } catch (error) {
    console.error("Syllabus Gen Error:", error);
    return [];
  }
};

export const generateUnitContent = async (
  courseName: string,
  unitTitle: string,
  level: string,
  languageCode: string = "en",
  quizConfig: { count: number; types: QuestionType[] } = { count: 3, types: ['mcq'] }
): Promise<{ content: string; questions: Question[] }> => {
  if (!ai) return { content: "Error loading content.", questions: [] };

  const lang = getLanguageName(languageCode);
  const typeStr = quizConfig.types.join(', ');

  try {
    // Split into two parallel requests to avoid token limits/truncation issues with large JSON responses
    const [contentResponse, quizResponse] = await Promise.all([
      // 1. Generate Lesson Content (Text/Markdown)
      ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Write a comprehensive, engaging educational lesson for ${courseName} (${level}) on the topic: "${unitTitle}".
        Output Language: ${lang}.

        Formatting Requirements:
        1. Use Markdown.
        2. STRUCTURE IS IMPORTANT: Use H2 headers (#) and H3 headers (##) frequently to break up sections.
        3. Use bullet points for lists.
        4. Use bold text for key terms.
        5. Use code blocks for examples.
        6. Explain concepts clearly with examples, avoiding massive walls of text.`,
      }),

      // 2. Generate Quiz Questions (JSON)
      ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate ${quizConfig.count} quiz questions for ${courseName} (${level}) on topic "${unitTitle}".
        Allowed Question Types: ${typeStr}.
        Output Language: ${lang}.
        IMPORTANT: The 'text', 'options', 'answer', and 'pairs' MUST be in ${lang}. However, keep specific code syntax or keywords in English/Code format if required.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              questions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    id: { type: Type.STRING },
                    type: { type: Type.STRING },
                    text: { type: Type.STRING },
                    options: { type: Type.ARRAY, items: { type: Type.STRING } },
                    correctIndex: { type: Type.INTEGER },
                    answer: { type: Type.STRING },
                    pairs: { 
                      type: Type.ARRAY, 
                      items: {
                        type: Type.OBJECT,
                        properties: {
                          term: { type: Type.STRING },
                          definition: { type: Type.STRING }
                        }
                      } 
                    }
                  },
                  required: ['text', 'type']
                }
              }
            },
            required: ['questions']
          }
        }
      })
    ]);

    const contentText = contentResponse.text || "No content generated.";
    const quizJson = JSON.parse(quizResponse.text || "{\"questions\": []}");

    // Add IDs if missing
    const questions = (quizJson.questions || []).map((q: any, i: number) => ({
      ...q,
      id: q.id || `q_${Date.now()}_${i}`
    }));

    return {
      content: contentText,
      questions: questions
    };

  } catch (error) {
    console.error("Unit Content Gen Error:", error);
    return {
      content: "Failed to generate content. Please try again.",
      questions: []
    };
  }
};

export const fetchVideos = async (
  topic: string, 
  languageCode: string
): Promise<Video[]> => {
  if (!ai) return [];

  const lang = getLanguageName(languageCode);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Find 3 helpful YouTube video tutorials for the topic: "${topic}".
      Language: ${lang}.

      Instructions:
      1. Use Google Search to find video IDs.
      2. Prefer official tutorials or high-quality educational channels that allow embedding.
      3. Return ONLY a JSON object.

      JSON Schema:
      {
        "videos": [
          { "title": "string", "videoId": "string (11 char ID ONLY)", "description": "short string" }
        ]
      }`,
      config: {
        tools: [{googleSearch: {}}],
        responseMimeType: "application/json"
      }
    });

    const jsonText = response.text || "{}";
    const data = JSON.parse(jsonText);

    // Robust ID extraction/sanitization
    const videos = (data.videos || []).map((v: any) => {
      // If the AI returns a full URL, extract the ID
      let id = v.videoId;
      if (id.length > 11) {
        const match = id.match(/(?:youtu\.be\/|youtube\.com\/(?:embed\/|v\/|watch\?v=|watch\?.+&v=))([^&?]+)/);
        if (match) id = match[1];
      }
      return { ...v, videoId: id };
    });

    return videos;
  } catch (error) {
    console.error("Fetch Videos Error:", error);
    return [];
  }
};

