import { LayoutGrid, BookOpen, Settings as SettingsIcon, ChevronRight, Wand2, Sparkles } from 'lucide-react';

const MainContent = () => {
  const { 
    t, 
    courses,
    selectedCourse, 
    selectCourse, 
    selectedLevel, 
    selectLevel, 
    selectedUnit, 
    selectUnit,
    updateCourseUnits,
    language
  } = useApp();

  const [showSettings, setShowSettings] = useState(false);
  const [syllabusFocus, setSyllabusFocus] = useState('');
